     1→/* tls_g.c - Handle tls/ssl using GNUTLS. */
     2→/* $OpenLDAP$ */
     3→/* This work is part of OpenLDAP Software <http://www.openldap.org/>.
     4→ *
     5→ * Copyright 2008-2022 The OpenLDAP Foundation.
     6→ * All rights reserved.
     7→ *
     8→ * Redistribution and use in source and binary forms, with or without
     9→ * modification, are permitted only as authorized by the OpenLDAP
    10→ * Public License.
    11→ *
    12→ * A copy of this license is available in the file LICENSE in the
    13→ * top-level directory of the distribution or, alternatively, at
    14→ * <http://www.OpenLDAP.org/license.html>.
    15→ */
    16→/* ACKNOWLEDGEMENTS: GNUTLS support written by Howard Chu and
    17→ * Emily Backes; sponsored by The Written Word (thewrittenword.com)
    18→ * and Stanford University (stanford.edu).
    19→ */
    20→
    21→#include "portable.h"
    22→
    23→#ifdef HAVE_GNUTLS
    24→
    25→#include "ldap_config.h"
    26→
    27→#include <stdio.h>
    28→
    29→#include <ac/stdlib.h>
    30→#include <ac/errno.h>
    31→#include <ac/socket.h>
    32→#include <ac/string.h>
    33→#include <ac/ctype.h>
    34→#include <ac/time.h>
    35→#include <ac/unistd.h>
    36→#include <ac/param.h>
    37→#include <ac/dirent.h>
    38→#include <sys/stat.h>
    39→#include <fcntl.h>
    40→
    41→#include "ldap-int.h"
    42→#include "ldap-tls.h"
    43→
    44→#include <gnutls/gnutls.h>
    45→#include <gnutls/x509.h>
    46→#include <gnutls/abstract.h>
    47→#include <gnutls/crypto.h>
    48→
    49→typedef struct tlsg_ctx {
    50→	gnutls_certificate_credentials_t cred;
    51→	gnutls_dh_params_t dh_params;
    52→	unsigned long verify_depth;
    53→	int refcount;
    54→	int reqcert;
    55→	gnutls_priority_t prios;
    56→#ifdef LDAP_R_COMPILE
    57→	ldap_pvt_thread_mutex_t ref_mutex;
    58→#endif
    59→} tlsg_ctx;
    60→
    61→typedef struct tlsg_session {
    62→	gnutls_session_t session;
    63→	tlsg_ctx *ctx;
    64→	struct berval peer_der_dn;
    65→} tlsg_session;
    66→
    67→static int tlsg_parse_ciphers( tlsg_ctx *ctx, char *suites );
    68→static int tlsg_cert_verify( tlsg_session *s );
    69→
    70→#ifdef LDAP_R_COMPILE
    71→
    72→static void
    73→tlsg_thr_init( void )
    74→{
    75→	/* do nothing */
    76→}
    77→#endif /* LDAP_R_COMPILE */
    78→
    79→/*
    80→ * Initialize TLS subsystem. Should be called only once.
    81→ */
    82→static int
    83→tlsg_init( void )
    84→{
    85→	gnutls_global_init();
    86→	return 0;
    87→}
    88→
    89→/*
    90→ * Tear down the TLS subsystem. Should only be called once.
    91→ */
    92→static void
    93→tlsg_destroy( void )
    94→{
    95→	gnutls_global_deinit();
    96→}
    97→
    98→static tls_ctx *
    99→tlsg_ctx_new ( struct ldapoptions *lo )
   100→{
   101→	tlsg_ctx *ctx;
   102→
   103→	ctx = ber_memcalloc ( 1, sizeof (*ctx) );
   104→	if ( ctx ) {
   105→		if ( gnutls_certificate_allocate_credentials( &ctx->cred )) {
   106→			ber_memfree( ctx );
   107→			return NULL;
   108→		}
   109→		ctx->refcount = 1;
   110→		gnutls_priority_init( &ctx->prios, "NORMAL", NULL );
   111→#ifdef LDAP_R_COMPILE
   112→		ldap_pvt_thread_mutex_init( &ctx->ref_mutex );
   113→#endif
   114→	}
   115→	return (tls_ctx *)ctx;
   116→}
   117→
   118→static void
   119→tlsg_ctx_ref( tls_ctx *ctx )
   120→{
   121→	tlsg_ctx *c = (tlsg_ctx *)ctx;
   122→	LDAP_MUTEX_LOCK( &c->ref_mutex );
   123→	c->refcount++;
   124→	LDAP_MUTEX_UNLOCK( &c->ref_mutex );
   125→}
   126→
   127→static void
   128→tlsg_ctx_free ( tls_ctx *ctx )
   129→{
   130→	tlsg_ctx *c = (tlsg_ctx *)ctx;
   131→	int refcount;
   132→
   133→	if ( !c ) return;
   134→
   135→	LDAP_MUTEX_LOCK( &c->ref_mutex );
   136→	refcount = --c->refcount;
   137→	LDAP_MUTEX_UNLOCK( &c->ref_mutex );
   138→	if ( refcount )
   139→		return;
   140→	gnutls_priority_deinit( c->prios );
   141→	gnutls_certificate_free_credentials( c->cred );
   142→	if ( c->dh_params )
   143→		gnutls_dh_params_deinit( c->dh_params );
   144→	ber_memfree ( c );
   145→}
   146→
   147→static int
   148→tlsg_getfile( const char *path, gnutls_datum_t *buf )
   149→{
   150→	int rc = -1, fd;
   151→	struct stat st;
   152→	char ebuf[128];
   153→
   154→	fd = open( path, O_RDONLY );
   155→	if ( fd < 0 ) {
   156→		Debug2( LDAP_DEBUG_ANY,
   157→			"TLS: opening `%s' failed: %s\n",
   158→			path,
   159→			AC_STRERROR_R( errno, ebuf, sizeof ebuf ));
   160→		return -1;
   161→	}
   162→	if ( fstat( fd, &st ) == 0 ) {
   163→		buf->size = st.st_size;
   164→		buf->data = LDAP_MALLOC( st.st_size + 1 );
   165→		if ( buf->data ) {
   166→			rc = read( fd, buf->data, st.st_size );
   167→			close( fd );
   168→			if ( rc < st.st_size )
   169→				rc = -1;
   170→			else
   171→				rc = 0;
   172→		}
   173→	}
   174→	return rc;
   175→}
   176→
   177→/* This is the GnuTLS default */
   178→#define	VERIFY_DEPTH	6
   179→
   180→/*
   181→ * initialize a new TLS context
   182→ */
   183→static int
   184→tlsg_ctx_init( struct ldapoptions *lo, struct ldaptls *lt, int is_server, char *errmsg )
   185→{
   186→	tlsg_ctx *ctx = lo->ldo_tls_ctx;
   187→	int rc;
   188→
   189→ 	if ( lo->ldo_tls_ciphersuite &&
   190→		tlsg_parse_ciphers( ctx, lt->lt_ciphersuite )) {
   191→		Debug1( LDAP_DEBUG_ANY,
   192→ 			   "TLS: could not set cipher list %s.\n",
   193→			   lo->ldo_tls_ciphersuite );
   194→		return -1;
   195→ 	}
   196→
   197→	if (lo->ldo_tls_cacertdir != NULL) {
   198→		char **dirs = ldap_str2charray( lt->lt_cacertdir, CERTPATHSEP );
   199→		int i;
   200→		for ( i=0; dirs[i]; i++ ) {
   201→			rc = gnutls_certificate_set_x509_trust_dir(
   202→				ctx->cred,
   203→				dirs[i],
   204→				GNUTLS_X509_FMT_PEM );
   205→			if ( rc > 0 ) {
   206→				Debug2( LDAP_DEBUG_TRACE,
   207→					"TLS: loaded %d CA certificates from directory `%s'.\n",
   208→					rc, dirs[i] );
   209→			} else {
   210→				Debug1( LDAP_DEBUG_ANY,
   211→					"TLS: warning: no certificate found in CA certificate directory `%s'.\n",
   212→					dirs[i] );
   213→				/* only warn, no return */
   214→				strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   215→			}
   216→		}
   217→		ldap_charray_free( dirs );
   218→	}
   219→
   220→	if (lo->ldo_tls_cacertfile != NULL) {
   221→		rc = gnutls_certificate_set_x509_trust_file( 
   222→			ctx->cred,
   223→			lt->lt_cacertfile,
   224→			GNUTLS_X509_FMT_PEM );
   225→		if ( rc < 0 ) {
   226→			Debug3( LDAP_DEBUG_ANY,
   227→				"TLS: could not use CA certificate file `%s': %s (%d)\n",
   228→				lo->ldo_tls_cacertfile,
   229→				gnutls_strerror( rc ),
   230→				rc );
   231→			return -1;
   232→		} else if ( rc == 0 ) {
   233→			Debug1( LDAP_DEBUG_ANY,
   234→				"TLS: warning: no certificate loaded from CA certificate file `%s'.\n",
   235→				lo->ldo_tls_cacertfile );
   236→			/* only warn, no return */
   237→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   238→		}
   239→	}
   240→
   241→	if (lo->ldo_tls_cacert.bv_val != NULL ) {
   242→		gnutls_datum_t buf;
   243→		buf.data = (unsigned char *)lo->ldo_tls_cacert.bv_val;
   244→		buf.size = lo->ldo_tls_cacert.bv_len;
   245→		rc = gnutls_certificate_set_x509_trust_mem(
   246→			ctx->cred,
   247→			&buf,
   248→			GNUTLS_X509_FMT_DER );
   249→		if ( rc < 0 ) {
   250→			Debug2( LDAP_DEBUG_ANY,
   251→				"TLS: could not use CA certificate: %s (%d)\n",
   252→				gnutls_strerror( rc ),
   253→				rc );
   254→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   255→			return -1;
   256→		}
   257→	}
   258→
   259→	if (( lo->ldo_tls_certfile && lo->ldo_tls_keyfile ) ||
   260→		( lo->ldo_tls_cert.bv_val && lo->ldo_tls_key.bv_val )) {
   261→		gnutls_x509_privkey_t key;
   262→		gnutls_datum_t buf;
   263→		gnutls_x509_crt_t certs[VERIFY_DEPTH];
   264→		unsigned int max = VERIFY_DEPTH;
   265→
   266→		rc = gnutls_x509_privkey_init( &key );
   267→		if ( rc ) {
   268→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   269→			return -1;
   270→		}
   271→
   272→		/* OpenSSL builds the cert chain for us, but GnuTLS
   273→		 * expects it to be present in the certfile. If it's
   274→		 * not, we have to build it ourselves. So we have to
   275→		 * do some special checks here...
   276→		 */
   277→		if ( lo->ldo_tls_key.bv_val ) {
   278→			buf.data = (unsigned char *)lo->ldo_tls_key.bv_val;
   279→			buf.size = lo->ldo_tls_key.bv_len;
   280→			rc = gnutls_x509_privkey_import( key, &buf,
   281→				GNUTLS_X509_FMT_DER );
   282→		} else {
   283→			rc = tlsg_getfile( lt->lt_keyfile, &buf );
   284→			if ( rc ) {
   285→				Debug1( LDAP_DEBUG_ANY,
   286→					"TLS: could not use private key file `%s`.\n",
   287→					lt->lt_keyfile);
   288→				return -1;
   289→			}
   290→			rc = gnutls_x509_privkey_import( key, &buf,
   291→				GNUTLS_X509_FMT_PEM );
   292→			LDAP_FREE( buf.data );
   293→		}
   294→		if ( rc < 0 ) {
   295→			Debug2( LDAP_DEBUG_ANY,
   296→				"TLS: could not use private key: %s (%d)\n",
   297→				gnutls_strerror( rc ),
   298→				rc );
   299→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   300→			return rc;
   301→		}
   302→
   303→		if ( lo->ldo_tls_cert.bv_val ) {
   304→			buf.data = (unsigned char *)lo->ldo_tls_cert.bv_val;
   305→			buf.size = lo->ldo_tls_cert.bv_len;
   306→			rc = gnutls_x509_crt_list_import( certs, &max, &buf,
   307→				GNUTLS_X509_FMT_DER, 0 );
   308→		} else {
   309→			rc = tlsg_getfile( lt->lt_certfile, &buf );
   310→			if ( rc ) {
   311→				Debug1( LDAP_DEBUG_ANY,
   312→					"TLS: could not use certificate file `%s`.\n",
   313→					lt->lt_certfile);
   314→				return -1;
   315→			}
   316→			rc = gnutls_x509_crt_list_import( certs, &max, &buf,
   317→				GNUTLS_X509_FMT_PEM, 0 );
   318→			LDAP_FREE( buf.data );
   319→		}
   320→		if ( rc < 0 ) {
   321→			Debug2( LDAP_DEBUG_ANY,
   322→				"TLS: could not use certificate: %s (%d)\n",
   323→				gnutls_strerror( rc ),
   324→				rc );
   325→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   326→			return rc;
   327→		}
   328→
   329→		/* If there's only one cert and it's not self-signed,
   330→		 * then we have to build the cert chain.
   331→		 */
   332→		if ( max == 1 && !gnutls_x509_crt_check_issuer( certs[0], certs[0] )) {
   333→			unsigned int i;
   334→			for ( i = 1; i<VERIFY_DEPTH; i++ ) {
   335→				if ( gnutls_certificate_get_issuer( ctx->cred, certs[i-1], &certs[i], 0 ))
   336→					break;
   337→				max++;
   338→				/* If this CA is self-signed, we're done */
   339→				if ( gnutls_x509_crt_check_issuer( certs[i], certs[i] ))
   340→					break;
   341→			}
   342→		}
   343→		rc = gnutls_certificate_set_x509_key( ctx->cred, certs, max, key );
   344→		if ( rc ) {
   345→			Debug2( LDAP_DEBUG_ANY,
   346→				"TLS: could not use certificate with key: %s (%d)\n",
   347→				gnutls_strerror( rc ),
   348→				rc );
   349→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   350→			return -1;
   351→		}
   352→	} else if (( lo->ldo_tls_certfile || lo->ldo_tls_keyfile )) {
   353→		Debug0( LDAP_DEBUG_ANY,
   354→		       "TLS: only one of certfile and keyfile specified\n" );
   355→		return -1;
   356→	} else if (( lo->ldo_tls_cert.bv_val || lo->ldo_tls_key.bv_val )) {
   357→		Debug0( LDAP_DEBUG_ANY,
   358→		       "TLS: only one of cert and key specified\n" );
   359→		return -1;
   360→	}
   361→
   362→	if ( lo->ldo_tls_crlfile ) {
   363→		rc = gnutls_certificate_set_x509_crl_file( 
   364→			ctx->cred,
   365→			lt->lt_crlfile,
   366→			GNUTLS_X509_FMT_PEM );
   367→		if ( rc < 0 ) {
   368→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   369→			return -1;
   370→		}
   371→		rc = 0;
   372→	}
   373→
   374→	/* FIXME: ITS#5992 - this should be configurable,
   375→	 * and V1 CA certs should be phased out ASAP.
   376→	 */
   377→	gnutls_certificate_set_verify_flags( ctx->cred,
   378→		GNUTLS_VERIFY_ALLOW_X509_V1_CA_CRT );
   379→
   380→	if ( is_server && lo->ldo_tls_dhfile ) {
   381→		gnutls_datum_t buf;
   382→		rc = tlsg_getfile( lo->ldo_tls_dhfile, &buf );
   383→		if ( rc ) return -1;
   384→		rc = gnutls_dh_params_init( &ctx->dh_params );
   385→		if ( rc == 0 )
   386→			rc = gnutls_dh_params_import_pkcs3( ctx->dh_params, &buf,
   387→				GNUTLS_X509_FMT_PEM );
   388→		LDAP_FREE( buf.data );
   389→		if ( rc ) {
   390→			strncpy( errmsg, gnutls_strerror( rc ), ERRBUFSIZE );
   391→			return -1;
   392→		}
   393→		gnutls_certificate_set_dh_params( ctx->cred, ctx->dh_params );
   394→	}
   395→
   396→	ctx->reqcert = lo->ldo_tls_require_cert;
   397→
   398→	return 0;
   399→}
