   401→static tls_session *
   402→tlsg_session_new ( tls_ctx * ctx, int is_server )
   403→{
   404→	tlsg_ctx *c = (tlsg_ctx *)ctx;
   405→	tlsg_session *session;
   406→
   407→	session = ber_memcalloc ( 1, sizeof (*session) );
   408→	if ( !session )
   409→		return NULL;
   410→
   411→	session->ctx = c;
   412→	gnutls_init( &session->session, is_server ? GNUTLS_SERVER : GNUTLS_CLIENT );
   413→	gnutls_priority_set( session->session, c->prios );
   414→	if ( c->cred )
   415→		gnutls_credentials_set( session->session, GNUTLS_CRD_CERTIFICATE, c->cred );
   416→	
   417→	if ( is_server ) {
   418→		int flag = 0;
   419→		if ( c->reqcert ) {
   420→			flag = GNUTLS_CERT_REQUEST;
   421→			if ( c->reqcert == LDAP_OPT_X_TLS_DEMAND ||
   422→				c->reqcert == LDAP_OPT_X_TLS_HARD )
   423→				flag = GNUTLS_CERT_REQUIRE;
   424→			gnutls_certificate_server_set_request( session->session, flag );
   425→		}
   426→	}
   427→	return (tls_session *)session;
   428→} 
   429→
   430→static int
   431→tlsg_session_accept( tls_session *session )
   432→{
   433→	tlsg_session *s = (tlsg_session *)session;
   434→	int rc;
   435→
   436→	rc = gnutls_handshake( s->session );
   437→	if ( rc == 0 && s->ctx->reqcert != LDAP_OPT_X_TLS_NEVER ) {
   438→		const gnutls_datum_t *peer_cert_list;
   439→		unsigned int list_size;
   440→
   441→		peer_cert_list = gnutls_certificate_get_peers( s->session, 
   442→						&list_size );
   443→		if ( !peer_cert_list && s->ctx->reqcert == LDAP_OPT_X_TLS_TRY )
   444→			rc = 0;
   445→		else {
   446→			rc = tlsg_cert_verify( s );
   447→			if ( rc && s->ctx->reqcert == LDAP_OPT_X_TLS_ALLOW )
   448→				rc = 0;
   449→		}
   450→	}
   451→	return rc;
   452→}
