   454→static int
   455→tlsg_session_connect( LDAP *ld, tls_session *session, const char *name_in )
   456→{
   457→	tlsg_session *s = (tlsg_session *)session;
   458→	int rc;
   459→
   460→	if ( name_in ) {
   461→		rc = gnutls_server_name_set( s->session, GNUTLS_NAME_DNS, name_in, strlen(name_in) );
   462→		if ( rc != GNUTLS_E_SUCCESS ) {
   463→			return rc;
   464→		}
   465→	}
   466→
   467→	return tlsg_session_accept( session);
   468→}
