   495→static void
   496→tlsg_x509_cert_dn( struct berval *cert, struct berval *dn, int get_subject )
   497→{
   498→	BerElementBuffer berbuf;
   499→	BerElement *ber = (BerElement *)&berbuf;
   500→	ber_tag_t tag;
   501→	ber_len_t len;
   502→	ber_int_t i;
   503→
   504→	ber_init2( ber, cert, LBER_USE_DER );
   505→	tag = ber_skip_tag( ber, &len );	/* Sequence */
   506→	tag = ber_skip_tag( ber, &len );	/* Sequence */
   507→	tag = ber_peek_tag( ber, &len );	/* Context + Constructed (version) */
   508→	if ( tag == 0xa0 ) {	/* Version is optional */
   509→		tag = ber_skip_tag( ber, &len );
   510→		tag = ber_get_int( ber, &i );	/* Int: Version */
   511→	}
   512→	tag = ber_skip_tag( ber, &len );	/* Int: Serial (can be longer than ber_int_t) */
   513→	ber_skip_data( ber, len );
   514→	tag = ber_skip_tag( ber, &len );	/* Sequence: Signature */
   515→	ber_skip_data( ber, len );
   516→	if ( !get_subject ) {
   517→		tag = ber_peek_tag( ber, &len );	/* Sequence: Issuer DN */
   518→	} else {
   519→		tag = ber_skip_tag( ber, &len );
   520→		ber_skip_data( ber, len );
   521→		tag = ber_skip_tag( ber, &len );	/* Sequence: Validity */
   522→		ber_skip_data( ber, len );
   523→		tag = ber_peek_tag( ber, &len );	/* Sequence: Subject DN */
   524→	}
   525→	len = ber_ptrlen( ber );
   526→	dn->bv_val = cert->bv_val + len;
   527→	dn->bv_len = cert->bv_len - len;
   528→}
