   530→static int
   531→tlsg_session_my_dn( tls_session *session, struct berval *der_dn )
   532→{
   533→	tlsg_session *s = (tlsg_session *)session;
   534→	const gnutls_datum_t *x;
   535→	struct berval bv;
   536→
   537→	x = gnutls_certificate_get_ours( s->session );
   538→
   539→	if (!x) return LDAP_INVALID_CREDENTIALS;
   540→	
   541→	bv.bv_val = (char *) x->data;
   542→	bv.bv_len = x->size;
   543→
   544→	tlsg_x509_cert_dn( &bv, der_dn, 1 );
   545→	return 0;
   546→}
   547→
   548→static int
   549→tlsg_session_peer_dn( tls_session *session, struct berval *der_dn )
   550→{
   551→	tlsg_session *s = (tlsg_session *)session;
   552→	if ( !s->peer_der_dn.bv_val ) {
   553→		const gnutls_datum_t *peer_cert_list;
   554→		unsigned int list_size;
   555→		struct berval bv;
   556→
   557→		peer_cert_list = gnutls_certificate_get_peers( s->session, 
   558→							&list_size );
   559→		if ( !peer_cert_list ) return LDAP_INVALID_CREDENTIALS;
   560→
   561→		bv.bv_len = peer_cert_list->size;
   562→		bv.bv_val = (char *) peer_cert_list->data;
   563→
   564→		tlsg_x509_cert_dn( &bv, &s->peer_der_dn, 1 );
   565→	}
   566→	*der_dn = s->peer_der_dn;
   567→	return 0;
   568→}
   569→
   570→/* what kind of hostname were we given? */
   571→#define	IS_DNS	0
   572→#define	IS_IP4	1
   573→#define	IS_IP6	2
   574→
   575→#define	CN_OID	"2.5.4.3"
   576→
   577→static int
   578→tlsg_session_chkhost( LDAP *ld, tls_session *session, const char *name_in )
   579→{
   580→	tlsg_session *s = (tlsg_session *)session;
   581→	int i, ret;
   582→	int chkSAN = ld->ld_options.ldo_tls_require_san, gotSAN = 0;
   583→	const gnutls_datum_t *peer_cert_list;
   584→	unsigned int list_size;
   585→	char altname[NI_MAXHOST];
   586→	size_t altnamesize;
   587→
   588→	gnutls_x509_crt_t cert;
   589→	const char *name;
   590→	char *ptr;
   591→	char *domain = NULL;
   592→#ifdef LDAP_PF_INET6
   593→	struct in6_addr addr;
   594→#else
   595→	struct in_addr addr;
   596→#endif
   597→	int len1 = 0, len2 = 0;
   598→	int ntype = IS_DNS;
   599→
   600→	if( ldap_int_hostname &&
   601→		( !name_in || !strcasecmp( name_in, "localhost" ) ) )
   602→	{
   603→		name = ldap_int_hostname;
   604→	} else {
   605→		name = name_in;
   606→	}
   607→
   608→	peer_cert_list = gnutls_certificate_get_peers( s->session, 
   609→						&list_size );
   610→	if ( !peer_cert_list ) {
   611→		Debug0( LDAP_DEBUG_ANY,
   612→			"TLS: unable to get peer certificate.\n" );
   613→		/* If this was a fatal condition, things would have
   614→		 * aborted long before now.
   615→		 */
   616→		return LDAP_SUCCESS;
   617→	}
   618→	ret = gnutls_x509_crt_init( &cert );
   619→	if ( ret < 0 )
   620→		return LDAP_LOCAL_ERROR;
   621→	ret = gnutls_x509_crt_import( cert, peer_cert_list, GNUTLS_X509_FMT_DER );
   622→	if ( ret ) {
   623→		gnutls_x509_crt_deinit( cert );
   624→		return LDAP_LOCAL_ERROR;
   625→	}
   626→
   627→#ifdef LDAP_PF_INET6
   628→	if (inet_pton(AF_INET6, name, &addr)) {
   629→		ntype = IS_IP6;
   630→	} else 
   631→#endif
   632→	if ((ptr = strrchr(name, '.')) && isdigit((unsigned char)ptr[1])) {
   633→		if (inet_aton(name, (struct in_addr *)&addr)) ntype = IS_IP4;
   634→	}
   635→	
   636→	if (ntype == IS_DNS) {
   637→		len1 = strlen(name);
   638→		domain = strchr(name, '.');
   639→		if (domain) {
   640→			len2 = len1 - (domain-name);
   641→		}
   642→	}
   643→
   644→	if (chkSAN) {
   645→	for ( i=0, ret=0; ret >= 0; i++ ) {
   646→		altnamesize = sizeof(altname);
   647→		ret = gnutls_x509_crt_get_subject_alt_name( cert, i, 
   648→			altname, &altnamesize, NULL );
   649→		if ( ret < 0 ) break;
   650→
   651→		gotSAN = 1;
   652→		/* ignore empty */
   653→		if ( altnamesize == 0 ) continue;
   654→
   655→		if ( ret == GNUTLS_SAN_DNSNAME ) {
   656→			if (ntype != IS_DNS) continue;
   657→	
   658→			/* Is this an exact match? */
   659→			if ((len1 == altnamesize) && !strncasecmp(name, altname, len1)) {
   660→				break;
   661→			}
   662→
   663→			/* Is this a wildcard match? */
   664→			if (domain && (altname[0] == '*') && (altname[1] == '.') &&
   665→				(len2 == altnamesize-1) && !strncasecmp(domain, &altname[1], len2))
   666→			{
   667→				break;
   668→			}
   669→		} else if ( ret == GNUTLS_SAN_IPADDRESS ) {
   670→			if (ntype == IS_DNS) continue;
   671→
   672→#ifdef LDAP_PF_INET6
   673→			if (ntype == IS_IP6 && altnamesize != sizeof(struct in6_addr)) {
   674→				continue;
   675→			} else
   676→#endif
   677→			if (ntype == IS_IP4 && altnamesize != sizeof(struct in_addr)) {
   678→				continue;
   679→			}
   680→			if (!memcmp(altname, &addr, altnamesize)) {
   681→				break;
   682→			}
   683→		}
   684→	}
   685→	if ( ret >= 0 ) {
   686→		ret = LDAP_SUCCESS;
   687→	}
   688→	}
   689→	if (ret != LDAP_SUCCESS && chkSAN) {
   690→		switch(chkSAN) {
   691→		case LDAP_OPT_X_TLS_DEMAND:
   692→		case LDAP_OPT_X_TLS_HARD:
   693→			if (!gotSAN) {
   694→				Debug0( LDAP_DEBUG_ANY,
   695→					"TLS: unable to get subjectAltName from peer certificate.\n" );
   696→				ret = LDAP_CONNECT_ERROR;
   697→				if ( ld->ld_error ) {
   698→					LDAP_FREE( ld->ld_error );
   699→				}
   700→				ld->ld_error = LDAP_STRDUP(
   701→					_("TLS: unable to get subjectAltName from peer certificate"));
   702→				goto done;
   703→			}
   704→			/* FALLTHRU */
   705→		case LDAP_OPT_X_TLS_TRY:
   706→			if (gotSAN) {
   707→				Debug1( LDAP_DEBUG_ANY, "TLS: hostname (%s) does not match "
   708→					"subjectAltName in certificate.\n",
   709→					name );
   710→				ret = LDAP_CONNECT_ERROR;
   711→				if ( ld->ld_error ) {
   712→					LDAP_FREE( ld->ld_error );
   713→				}
   714→				ld->ld_error = LDAP_STRDUP(
   715→					_("TLS: hostname does not match subjectAltName in peer certificate"));
   716→				goto done;
   717→			}
   718→			break;
   719→		case LDAP_OPT_X_TLS_ALLOW:
   720→			break;
   721→		}
   722→	}
   723→
   724→	if ( ret != LDAP_SUCCESS ){
   725→		/* find the last CN */
   726→		i=0;
   727→		do {
   728→			altnamesize = 0;
   729→			ret = gnutls_x509_crt_get_dn_by_oid( cert, CN_OID,
   730→				i, 1, altname, &altnamesize );
   731→			if ( ret == GNUTLS_E_SHORT_MEMORY_BUFFER )
   732→				i++;
   733→			else
   734→				break;
   735→		} while ( 1 );
   736→
   737→		if ( i ) {
   738→			altnamesize = sizeof(altname);
   739→			ret = gnutls_x509_crt_get_dn_by_oid( cert, CN_OID,
   740→				i-1, 0, altname, &altnamesize );
   741→		}
   742→
   743→		if ( ret < 0 ) {
   744→			Debug0( LDAP_DEBUG_ANY,
   745→				"TLS: unable to get common name from peer certificate.\n" );
   746→			ret = LDAP_CONNECT_ERROR;
   747→			if ( ld->ld_error ) {
   748→				LDAP_FREE( ld->ld_error );
   749→			}
   750→			ld->ld_error = LDAP_STRDUP(
   751→				_("TLS: unable to get CN from peer certificate"));
   752→
   753→		} else {
   754→			ret = LDAP_LOCAL_ERROR;
   755→			if ( !len1 ) len1 = strlen( name );
   756→			if ( len1 == altnamesize && strncasecmp(name, altname, altnamesize) == 0 ) {
   757→				ret = LDAP_SUCCESS;
   758→
   759→			} else if (( altname[0] == '*' ) && ( altname[1] == '.' )) {
   760→					/* Is this a wildcard match? */
   761→				if( domain &&
   762→					(len2 == altnamesize-1) && !strncasecmp(domain, &altname[1], len2)) {
   763→					ret = LDAP_SUCCESS;
   764→				}
   765→			}
   766→		}
   767→
   768→		if( ret == LDAP_LOCAL_ERROR ) {
   769→			altname[altnamesize] = '\0';
   770→			Debug2( LDAP_DEBUG_ANY, "TLS: hostname (%s) does not match "
   771→				"common name in certificate (%s).\n", 
   772→				name, altname );
   773→			ret = LDAP_CONNECT_ERROR;
   774→			if ( ld->ld_error ) {
   775→				LDAP_FREE( ld->ld_error );
   776→			}
   777→			ld->ld_error = LDAP_STRDUP(
   778→				_("TLS: hostname does not match name in peer certificate"));
   779→		}
   780→	}
   781→done:
   782→	gnutls_x509_crt_deinit( cert );
   783→	return ret;
   784→}
