   786→static int
   787→tlsg_session_strength( tls_session *session )
   788→{
   789→	tlsg_session *s = (tlsg_session *)session;
   790→	gnutls_cipher_algorithm_t c;
   791→
   792→	c = gnutls_cipher_get( s->session );
   793→	return gnutls_cipher_get_key_size( c ) * 8;
   794→}
   795→
   796→static int
   797→tlsg_session_unique( tls_session *sess, struct berval *buf, int is_server)
   798→{
   799→	tlsg_session *s = (tlsg_session *)sess;
   800→	gnutls_datum_t cb;
   801→	int rc;
   802→
   803→	rc = gnutls_session_channel_binding( s->session, GNUTLS_CB_TLS_UNIQUE, &cb );
   804→	if ( rc == 0 ) {
   805→		int len = cb.size;
   806→		if ( len > buf->bv_len )
   807→			len = buf->bv_len;
   808→		buf->bv_len = len;
   809→		memcpy( buf->bv_val, cb.data, len );
   810→		return len;
   811→	}
   812→	return 0;
   813→}
   814→
   815→static int
   816→tlsg_session_endpoint( tls_session *sess, struct berval *buf, int is_server )
   817→{
   818→	tlsg_session *s = (tlsg_session *)sess;
   819→	const gnutls_datum_t *cert_data;
   820→	gnutls_x509_crt_t server_cert;
   821→	gnutls_digest_algorithm_t md;
   822→	int sign_algo, md_len, rc;
   823→
   824→	if ( is_server )
   825→		cert_data = gnutls_certificate_get_ours( s->session );
   826→	else
   827→		cert_data = gnutls_certificate_get_peers( s->session, NULL );
   828→
   829→	if ( cert_data == NULL )
   830→		return 0;
   831→
   832→	rc = gnutls_x509_crt_init( &server_cert );
   833→	if ( rc != GNUTLS_E_SUCCESS )
   834→		return 0;
   835→
   836→	rc = gnutls_x509_crt_import( server_cert, cert_data, GNUTLS_X509_FMT_DER );
   837→	if ( rc != GNUTLS_E_SUCCESS ) {
   838→		gnutls_x509_crt_deinit( server_cert );
   839→		return 0;
   840→	}
   841→
   842→	sign_algo = gnutls_x509_crt_get_signature_algorithm( server_cert );
   843→	gnutls_x509_crt_deinit( server_cert );
   844→	if ( sign_algo <= GNUTLS_SIGN_UNKNOWN )
   845→		return 0;
   846→
   847→	md = gnutls_sign_get_hash_algorithm( sign_algo );
   848→	if ( md == GNUTLS_DIG_UNKNOWN )
   849→		return 0;
   850→
   851→	/* See RFC 5929 */
   852→	switch (md) {
   853→	case GNUTLS_DIG_NULL:
   854→	case GNUTLS_DIG_MD2:
   855→	case GNUTLS_DIG_MD5:
   856→	case GNUTLS_DIG_SHA1:
   857→		md = GNUTLS_DIG_SHA256;
   858→	}
   859→
   860→	md_len = gnutls_hash_get_len( md );
   861→	if ( md_len == 0 || md_len > buf->bv_len )
   862→		return 0;
   863→
   864→	rc = gnutls_hash_fast( md, cert_data->data, cert_data->size, buf->bv_val );
   865→	if ( rc != GNUTLS_E_SUCCESS )
   866→		return 0;
   867→
   868→	buf->bv_len = md_len;
   869→
   870→	return md_len;
   871→}
   872→
   873→static const char *
   874→tlsg_session_version( tls_session *sess )
   875→{
   876→	tlsg_session *s = (tlsg_session *)sess;
   877→	return gnutls_protocol_get_name(gnutls_protocol_get_version( s->session ));
