   887→static int
   888→tlsg_session_peercert( tls_session *sess, struct berval *der )
   889→{
   890→	tlsg_session *s = (tlsg_session *)sess;
   891→	const gnutls_datum_t *peer_cert_list;
   892→	unsigned int list_size;
   893→
   894→	peer_cert_list = gnutls_certificate_get_peers( s->session, &list_size );
   895→	if (!peer_cert_list)
   896→		return -1;
   897→	der->bv_len = peer_cert_list[0].size;
   898→	der->bv_val = LDAP_MALLOC( der->bv_len );
   899→	if (!der->bv_val)
   900→		return -1;
   901→	memcpy(der->bv_val, peer_cert_list[0].data, der->bv_len);
   902→	return 0;
   903→}
   904→
   905→static int
   906→tlsg_session_pinning( LDAP *ld, tls_session *sess, char *hashalg, struct berval *hash )
   907→{
   908→	tlsg_session *s = (tlsg_session *)sess;
   909→	const gnutls_datum_t *cert_list;
   910→	unsigned int cert_list_size = 0;
   911→	gnutls_x509_crt_t crt;
   912→	gnutls_pubkey_t pubkey;
   913→	gnutls_datum_t key = {};
   914→	gnutls_digest_algorithm_t alg;
   915→	struct berval keyhash;
   916→	size_t len;
   917→	int rc = -1;
   918→
   919→	if ( hashalg ) {
   920→		alg = gnutls_digest_get_id( hashalg );
   921→		if ( alg == GNUTLS_DIG_UNKNOWN ) {
   922→			Debug1( LDAP_DEBUG_ANY, "tlsg_session_pinning: "
   923→					"unknown hashing algorithm for GnuTLS: '%s'\n",
   924→					hashalg );
   925→			return rc;
   926→		}
   927→	}
   928→
   929→	cert_list = gnutls_certificate_get_peers( s->session, &cert_list_size );
   930→	if ( cert_list_size == 0 ) {
   931→		return rc;
   932→	}
   933→
   934→	if ( gnutls_x509_crt_init( &crt ) < 0 ) {
   935→		return rc;
   936→	}
   937→
   938→	if ( gnutls_x509_crt_import( crt, &cert_list[0], GNUTLS_X509_FMT_DER ) ) {
   939→		goto done;
   940→	}
   941→
   942→	if ( gnutls_pubkey_init( &pubkey ) ) {
   943→		goto done;
   944→	}
   945→
   946→	if ( gnutls_pubkey_import_x509( pubkey, crt, 0 ) < 0 ) {
   947→		goto done;
   948→	}
   949→
   950→	gnutls_pubkey_export( pubkey, GNUTLS_X509_FMT_DER, key.data, &len );
   951→	if ( len <= 0 ) {
   952→		goto done;
   953→	}
   954→
   955→	key.data = LDAP_MALLOC( len );
   956→	if ( !key.data ) {
   957→		goto done;
   958→	}
   959→
   960→	key.size = len;
   961→
   962→	if ( gnutls_pubkey_export( pubkey, GNUTLS_X509_FMT_DER,
   963→				key.data, &len ) < 0 ) {
   964→		goto done;
   965→	}
   966→
   967→	if ( hashalg ) {
   968→		keyhash.bv_len = gnutls_hash_get_len( alg );
   969→		keyhash.bv_val = LDAP_MALLOC( keyhash.bv_len );
   970→		if ( !keyhash.bv_val || gnutls_fingerprint( alg, &key,
   971→					keyhash.bv_val, &keyhash.bv_len ) < 0 ) {
   972→			goto done;
   973→		}
   974→	} else {
   975→		keyhash.bv_val = (char *)key.data;
   976→		keyhash.bv_len = key.size;
   977→	}
   978→
   979→	if ( ber_bvcmp( hash, &keyhash ) ) {
   980→		rc = LDAP_CONNECT_ERROR;
   981→		Debug0( LDAP_DEBUG_ANY, "tlsg_session_pinning: "
   982→				"public key hash does not match provided pin.\n" );
   983→		if ( ld->ld_error ) {
   984→			LDAP_FREE( ld->ld_error );
   985→		}
   986→		ld->ld_error = LDAP_STRDUP(
   987→			_("TLS: public key hash does not match provided pin"));
   988→	} else {
   989→		rc = LDAP_SUCCESS;
   990→	}
   991→
   992→done:
   993→	if ( pubkey ) {
   994→		gnutls_pubkey_deinit( pubkey );
   995→	}
   996→	if ( crt ) {
   997→		gnutls_x509_crt_deinit( crt );
   998→	}
   999→	if ( keyhash.bv_val != (char *)key.data ) {
  1000→		LDAP_FREE( keyhash.bv_val );
  1001→	}
  1002→	if ( key.data ) {
  1003→		LDAP_FREE( key.data );
  1004→	}
  1005→	return rc;
  1006→}
  1007→
  1008→/* suites is a string of colon-separated cipher suite names. */
  1009→static int
  1010→tlsg_parse_ciphers( tlsg_ctx *ctx, char *suites )
  1011→{
  1012→	const char *err;
  1013→	int rc = gnutls_priority_init( &ctx->prios, suites, &err );
  1014→	if ( rc )
  1015→		ctx->prios = NULL;
  1016→	return rc;
  1017→}
  1018→
  1019→/*
  1020→ * TLS support for LBER Sockbufs
  1021→ */
  1022→
  1023→struct tls_data {
  1024→	tlsg_session		*session;
  1025→	Sockbuf_IO_Desc		*sbiod;
  1026→};
  1027→
  1028→static ssize_t
  1029→tlsg_recv( gnutls_transport_ptr_t ptr, void *buf, size_t len )
  1030→{
  1031→	struct tls_data		*p;
  1032→
  1033→	if ( buf == NULL || len <= 0 ) return 0;
  1034→
  1035→	p = (struct tls_data *)ptr;
  1036→
  1037→	if ( p == NULL || p->sbiod == NULL ) {
  1038→		return 0;
  1039→	}
  1040→
  1041→	return LBER_SBIOD_READ_NEXT( p->sbiod, buf, len );
  1042→}
  1043→
  1044→static ssize_t
  1045→tlsg_send( gnutls_transport_ptr_t ptr, const void *buf, size_t len )
  1046→{
  1047→	struct tls_data		*p;
  1048→	
  1049→	if ( buf == NULL || len <= 0 ) return 0;
  1050→	
  1051→	p = (struct tls_data *)ptr;
  1052→
  1053→	if ( p == NULL || p->sbiod == NULL ) {
  1054→		return 0;
  1055→	}
  1056→
  1057→	return LBER_SBIOD_WRITE_NEXT( p->sbiod, (char *)buf, len );
  1058→}
  1059→
  1060→static int
  1061→tlsg_sb_setup( Sockbuf_IO_Desc *sbiod, void *arg )
  1062→{
  1063→	struct tls_data		*p;
  1064→	tlsg_session	*session = arg;
  1065→
  1066→	assert( sbiod != NULL );
  1067→
  1068→	p = LBER_MALLOC( sizeof( *p ) );
  1069→	if ( p == NULL ) {
  1070→		return -1;
  1071→	}
  1072→	
  1073→	gnutls_transport_set_ptr( session->session, (gnutls_transport_ptr_t)p );
  1074→	gnutls_transport_set_pull_function( session->session, tlsg_recv );
  1075→	gnutls_transport_set_push_function( session->session, tlsg_send );
  1076→	p->session = session;
  1077→	p->sbiod = sbiod;
  1078→	sbiod->sbiod_pvt = p;
  1079→	return 0;
  1080→}
  1081→
  1082→static int
  1083→tlsg_sb_remove( Sockbuf_IO_Desc *sbiod )
  1084→{
  1085→	struct tls_data		*p;
  1086→	
  1087→	assert( sbiod != NULL );
  1088→	assert( sbiod->sbiod_pvt != NULL );
  1089→
  1090→	p = (struct tls_data *)sbiod->sbiod_pvt;
  1091→	gnutls_deinit ( p->session->session );
  1092→	LBER_FREE( p->session );
  1093→	LBER_FREE( sbiod->sbiod_pvt );
  1094→	sbiod->sbiod_pvt = NULL;
  1095→	return 0;
  1096→}
  1097→
  1098→static int
  1099→tlsg_sb_close( Sockbuf_IO_Desc *sbiod )
  1100→{
  1101→	struct tls_data		*p;
  1102→	
  1103→	assert( sbiod != NULL );
  1104→	assert( sbiod->sbiod_pvt != NULL );
  1105→
  1106→	p = (struct tls_data *)sbiod->sbiod_pvt;
  1107→	gnutls_bye ( p->session->session, GNUTLS_SHUT_WR );
  1108→	return 0;
  1109→}
  1110→
  1111→static int
  1112→tlsg_sb_ctrl( Sockbuf_IO_Desc *sbiod, int opt, void *arg )
  1113→{
  1114→	struct tls_data		*p;
  1115→	
  1116→	assert( sbiod != NULL );
  1117→	assert( sbiod->sbiod_pvt != NULL );
  1118→
  1119→	p = (struct tls_data *)sbiod->sbiod_pvt;
  1120→	
  1121→	if ( opt == LBER_SB_OPT_GET_SSL ) {
  1122→		*((tlsg_session **)arg) = p->session;
  1123→		return 1;
  1124→		
  1125→	} else if ( opt == LBER_SB_OPT_DATA_READY ) {
  1126→		if( gnutls_record_check_pending( p->session->session ) > 0 ) {
  1127→			return 1;
  1128→		}
  1129→	}
  1130→	
  1131→	return LBER_SBIOD_CTRL_NEXT( sbiod, opt, arg );
  1132→}
  1133→
  1134→static ber_slen_t
  1135→tlsg_sb_read( Sockbuf_IO_Desc *sbiod, void *buf, ber_len_t len)
  1136→{
  1137→	struct tls_data		*p;
  1138→	ber_slen_t		ret;
  1139→
  1140→	assert( sbiod != NULL );
  1141→	assert( SOCKBUF_VALID( sbiod->sbiod_sb ) );
  1142→
  1143→	p = (struct tls_data *)sbiod->sbiod_pvt;
  1144→
  1145→	ret = gnutls_record_recv ( p->session->session, buf, len );
  1146→	switch (ret) {
  1147→	case GNUTLS_E_INTERRUPTED:
  1148→	case GNUTLS_E_AGAIN:
  1149→		sbiod->sbiod_sb->sb_trans_needs_read = 1;
  1150→		sock_errset(EWOULDBLOCK);
  1151→		ret = 0;
  1152→		break;
  1153→	case GNUTLS_E_REHANDSHAKE:
  1154→		for ( ret = gnutls_handshake ( p->session->session );
  1155→		      ret == GNUTLS_E_INTERRUPTED || ret == GNUTLS_E_AGAIN;
  1156→		      ret = gnutls_handshake ( p->session->session ) );
  1157→		sbiod->sbiod_sb->sb_trans_needs_read = 1;
  1158→		ret = 0;
  1159→		break;
  1160→	default:
  1161→		sbiod->sbiod_sb->sb_trans_needs_read = 0;
  1162→	}
  1163→	return ret;
  1164→}
  1165→
  1166→static ber_slen_t
  1167→tlsg_sb_write( Sockbuf_IO_Desc *sbiod, void *buf, ber_len_t len)
  1168→{
  1169→	struct tls_data		*p;
  1170→	ber_slen_t		ret;
  1171→
  1172→	assert( sbiod != NULL );
  1173→	assert( SOCKBUF_VALID( sbiod->sbiod_sb ) );
  1174→
  1175→	p = (struct tls_data *)sbiod->sbiod_pvt;
  1176→
  1177→	ret = gnutls_record_send ( p->session->session, (char *)buf, len );
  1178→
  1179→	if ( ret == GNUTLS_E_INTERRUPTED || ret == GNUTLS_E_AGAIN ) {
  1180→		sbiod->sbiod_sb->sb_trans_needs_write = 1;
  1181→		sock_errset(EWOULDBLOCK);
  1182→		ret = 0;
  1183→	} else {
  1184→		sbiod->sbiod_sb->sb_trans_needs_write = 0;
  1185→	}
  1186→	return ret;
  1187→}
  1188→
  1189→static Sockbuf_IO tlsg_sbio =
  1190→{
  1191→	tlsg_sb_setup,		/* sbi_setup */
  1192→	tlsg_sb_remove,		/* sbi_remove */
  1193→	tlsg_sb_ctrl,		/* sbi_ctrl */
  1194→	tlsg_sb_read,		/* sbi_read */
  1195→	tlsg_sb_write,		/* sbi_write */
  1196→	tlsg_sb_close		/* sbi_close */
  1197→};
