  1199→/* Certs are not automatically verified during the handshake */
  1200→static int
  1201→tlsg_cert_verify( tlsg_session *ssl )
  1202→{
  1203→	unsigned int status = 0;
  1204→	int err;
  1205→	time_t now = time(0);
  1206→	time_t peertime;
  1207→
  1208→	err = gnutls_certificate_verify_peers2( ssl->session, &status );
  1209→	if ( err < 0 ) {
  1210→		Debug1( LDAP_DEBUG_ANY,"TLS: gnutls_certificate_verify_peers2 failed %d\n",
  1211→			err );
  1212→		return -1;
  1213→	}
  1214→	if ( status ) {
  1215→		Debug1( LDAP_DEBUG_TRACE,"TLS: peer cert untrusted or revoked (0x%x)\n",
  1216→			status );
  1217→		return -1;
  1218→	}
  1219→	peertime = gnutls_certificate_expiration_time_peers( ssl->session );
  1220→	if ( peertime == (time_t) -1 ) {
  1221→		Debug0( LDAP_DEBUG_ANY, "TLS: gnutls_certificate_expiration_time_peers failed\n" );
  1222→		return -1;
  1223→	}
  1224→	if ( peertime < now ) {
  1225→		Debug0( LDAP_DEBUG_ANY, "TLS: peer certificate is expired\n" );
  1226→		return -1;
  1227→	}
  1228→	peertime = gnutls_certificate_activation_time_peers( ssl->session );
  1229→	if ( peertime == (time_t) -1 ) {
  1230→		Debug0( LDAP_DEBUG_ANY, "TLS: gnutls_certificate_activation_time_peers failed\n" );
  1231→		return -1;
  1232→	}
  1233→	if ( peertime > now ) {
  1234→		Debug0( LDAP_DEBUG_ANY, "TLS: peer certificate not yet active\n" );
  1235→		return -1;
  1236→	}
  1237→	return 0;
  1238→}
